mapper.select:
SELECT id, title, CASE WHEN content IS NOT NULL THEN content ELSE '' END AS content, excerpt, category, tags, author, source_url, quality, word_count, status, created_at, updated_at FROM knowledge_article
AND category = #{category}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR tags LIKE CONCAT('%', #{keyword}, '%') OR excerpt LIKE CONCAT('%', #{keyword}, '%'))
AND quality = #{quality} AND status = #{status}
ORDER BY updated_at DESC

mapper.update:
UPDATE knowledge_article
title = #{title}, content = #{content}, excerpt = #{excerpt}, category = #{category}, tags = #{tags}, author = #{author}, source_url = #{sourceUrl}, quality = #{quality}, word_count = #{wordCount}, status = #{status}, updated_at = NOW()
WHERE id = #{id}
